ad("*a");printDebugStmt("Fog system- fog data extracted from fog.cml");fogFile:close();else printDebugStmt("Fog system- Superloader's fog.xml could not be read. Aborting");return;end local mergedContent;local tagStart=rawContent:find("</effect>",1,true);if  not tagStart then printDebugStmt("Fog system- Proper XML tags not found in content. Aborting ");return;end local beforeTag=rawContent:sub(1,tagStart-1 );local afterTag=rawContent:sub(tagStart);mergedContent=beforeTag   .. fogContent   .. "\n"   .. afterTag ;printDebugStmt("Fog system- fog content successfully merged with original stadium server content. Ending </effect> tag was found at "   .. tagStart );local filepathWrite=""   .. contentRoot   .. "fog\\current\\fogConfig.xml" ;local fileToWrite=io.open(filepathWrite,"w");if fileToWrite then fileToWrite:write(mergedContent);printDebugStmt("Fog system- Final merged content successfully written to fogConfig.xml");fileToWrite:close();else printDebugStmt("Fog system- Target file fogConfig.xml could not be read. Aborting");return;end return "fog\\current\\fogConfig.xml";end function makeRainConfig(ctx,filename) printDebugStmt("Rain system- NR or DR effect config file was requested "   .. filename );local filepathRead=ctx.sider_dir   .. "\\content\\stadium-server\\"   .. ctx.stadium_path   .. "\\"   .. filename ;local fileToRead=io.open(filepathRead,"r");local rawContent;local contentWithout2DRain={};if fileToRead then rawContent=fileToRead:read("*a");printDebugStmt("Rain system- Content successfully read for effect_config_nr or dr.xml");for line in rawContent:gmatch("[^\r\n]+") do if ( not line:match('<create type="MultiUvScrollScreen"') and  not line:match('<create type="RainDemo"')) then table.insert(contentWithout2DRain,line);end end contentWithout2DRain=table.concat(contentWithout2DRain,"\n");printDebugStmt("Rain system- 2D rain related data removed from content");fileToRead:close();else printDebugStmt("Rain system- effect_config_nr or dr could not be read. Aborting");return;end local pathBasedOnSnowMod;if ((initTable.snow~="Disabled") and (ctx.weather==1) and (ctx.season==1)) then reinitialiseInitTable();printDebugStmt("Rain System- Snow was enabled so newRain.xml config will not be returned from current directory instead snowfall.xml will be returned");pathBasedOnSnowMod="snow\\current\\snowfall.xml";else pathBasedOnSnowMod="effects\\current\\newRain.xml";end local newRainFile=io.open(""   .. contentRoot   .. pathBasedOnSnowMod ,"r");local newRainContent;if newRainFile then newRainContent=newRainFile:read("*a");printDebugStmt("Rain system- 3d rain data was extracted from newRain.xml");newRainFile:close();else printDebugStmt("Rain system- Superloader's newRain.xml could not be read. Aborting");return;end local mergedContent;local tagStart=contentWithout2DRain:find("</effect>",1,true);if  not tagStart then printDebugStmt("Rain system- Proper XML tags not found in content. Aborting ");return;end local beforeTag=contentWithout2DRain:sub(1,tagStart-1 );local afterTag=contentWithout2DRain:sub(tagStart);mergedContent=beforeTag   .. newRainContent   .. "\n"   .. afterTag ;printDebugStmt("Rain system- 3d rain content successfully merged with original stadium server content. Ending </effect> tag was found at "   .. tagStart );local filepathWrite=""   .. contentRoot   .. "effects\\current\\rainConfig.xml" ;local fileToWrite=io.open(filepathWrite,"w");if fileToWrite then fileToWrite:write(mergedContent);printDebugStmt("Rain system- Final merged content successfully written to rainConfig.xml");fileToWrite:close();else printDebugStmt("Rain system- Target file rainConfig.xml could not be read. Aborting");return;end return "effects\\current\\rainConfig.xml";end function makeRainAndFogConfig(ctx,filename) printDebugStmt("Rain+Fog system- effect config file was requested "   .. filename );local filepathRead=ctx.sider_dir   .. "\\content\\stadium-server\\"   .. ctx.stadium_path   .. "\\"   .. filename ;local fileToRead=io.open(filepathRead,