found at "   .. tagStart );else printDebugStmt("Rain+Fog system- weather conditions for rain not met. Will now check if fog conditions were met");mergedContentWithRain=contentWithout2DRain;end local finalMergedContent;if (string.find(filename,"\\effect_config_nr.xml") or string.find(filename,"\\effect_config_dr.xml") or string.find(filename,"\\effect_config_df.xml") or string.find(filename,"\\effect_config_nf.xml")) then local fogFile=io.open(""   .. contentRoot   .. "fog\\current\\fog.xml" ,"r");local fogContent;if fogFile then fogContent=fogFile:read("*a");printDebugStmt("Rain+Fog system- fog data extracted from fog.cml");fogFile:close();else printDebugStmt("Rain+Fog system- Superloader's fog.xml could not be read. Aborting");return;end local tagStart=mergedContentWithRain:find("</effect>",1,true);if  not tagStart then printDebugStmt("Rain+Fog system- Proper XML tags not found in content. Aborting ");return;end local beforeTag=mergedContentWithRain:sub(1,tagStart-1 );local afterTag=mergedContentWithRain:sub(tagStart);finalMergedContent=beforeTag   .. fogContent   .. "\n"   .. afterTag ;printDebugStmt("Rain+Fog system- fog content successfully merged with original stadium server content + 3d rain content. Ending </effect> tag was found at "   .. tagStart );else printDebugStmt("Rain+Fog system- weather conditions for fog not met. Proceeding with only 3d rain if it was requested");finalMergedContent=mergedContentWithRain;end local filepathWrite=""   .. contentRoot   .. "fog\\current\\rainAndFogConfig.xml" ;local fileToWrite=io.open(filepathWrite,"w");if fileToWrite then fileToWrite:write(finalMergedContent);printDebugStmt("Rain+Fog system- Final merged content successfully written to fog/current/rainAndFogConfig.xml");fileToWrite:close();else printDebugStmt("Rain+Fog system- Target file fog/current/rainAndFogConfig.xml could not be read. Aborting");return;end return "fog\\current\\rainAndFogConfig.xml";end return {init=init}; end